import GridItem from "./GridItem";

export default function Grid({ items, selectedId, onSelect }) {
  return (
    <div
      style={{
        padding: "12px 20px",
        display: "grid",
        gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))",
        gap: "16px",
      }}
    >
      {items.map((item) => (
        <GridItem
          key={item.id}
          item={item}
          selected={selectedId === item.id}
          onClick={() => onSelect(item)}
        />
      ))}
    </div>
  );
}
